1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // === Simplest cases ===
6	  it("empty item list → premium 5 G (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // === Single main item base premiums (+ processing fee) ===
15	  it("single plain sword (no modifiers, 0 yrs, first contract) → 100 + 10 first + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single plain amulet → 60 + 10 first + 5 fee = 75 G", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 75 }] });
28	  });
29	  it.todo("single plain staff → 80 + 10 first + 5 fee = 95 G");
30	  it.todo("single plain potion → 40 + 10 first + 5 fee = 55 G");
31	
32	  // === Components ===
33	  it.todo("single rune → 25 + 10 first + 5 fee = 40 G");
34	  it.todo("single moonstone → 25 + 10 first + 5 fee = 40 G");
35	
36	  // === Building block of 3 alike components ===
37	  it.todo("2 runes → 50 G base premium (no block)");
38	  it.todo("3 runes → 60 G base premium (block applies)");
39	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
40	  it.todo("7 runes → 175 G base premium (3+3+1 → no block since block is exactly 3? spec: 7 runes 175)");
41	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
42	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
43	
44	  // === Item-specific modifiers ===
45	  it.todo("cursed sword adds 50% surcharge to the sword's base premium");
46	  it.todo("sword with enchantment exactly 5 → high-enchantment surcharge applies (30%)");
47	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
48	  it.todo("cursed sword with enchantment 5 → both surcharges apply");
49	
50	  // === Policy-wide modifiers ===
51	  it.todo("customer with exactly 2 years → loyalty discount (20%) applies");
52	  it.todo("customer with 1 year → no loyalty discount");
53	  it.todo("first ever insurance carries 10% initial assessment surcharge");
54	  it.todo("customer's second contract receives 15% follow-up discount");
55	
56	  // === Rounding ===
57	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
58	
59	  // === Integration examples ===
60	  it.todo("newcomer cursed sword (0 yrs, first contract, enchant 3) → premium 165 G");
61	  it.todo("long-standing customer's second cursed enchant-7 sword → premium 160 G");
62	
63	  // === Modifier scope on multi-item policies ===
64	  it.todo("cursed sword + plain amulet (0 yrs, first contract) → cursed surcharge on sword only");
65	
66	  // === Claim: basic reimbursement ===
67	  it.todo("regular sword (steel, enchant 3), damage 500 → payout 400 G (500 - 100 deductible)");
68	  it.todo("rune damage 200 → payout 100 G (200 - 100 deductible)");
69	
70	  // === Claim: enchantment threshold ===
71	  it.todo("steel sword enchant 9, damage 1000 → payout 400 G (50% then deductible)");
72	  it.todo("dragon-material sword enchant 9, damage 1000 → payout 400 G (50% wins, then deductible)");
73	  it.todo("dragon-material sword enchant 5, damage 800 → payout 700 G (full then deductible)");
74	  it.todo("dragon-material sword enchant exactly 8, damage 1000 → payout 400 G");
75	
76	  // === Claim: per-damage deductible ===
77	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");
78	
79	  // === Multiple items of same type ===
80	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G");
81	  it.todo("policy with two swords, dragon attack damages both → each is treated as separate damage");
82	  it.todo("damages array has more entries of a type than policy covers → CLI exits non-zero");
83	
84	  // === Cap ===
85	  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
86	  it.todo("cursed sword: cap based on unmodified insurance value → cap 2000 G");
87	  it.todo("sword + 3 runes (block) → insurance sum 1750 G");
88	  it.todo("sword cap 2000: first claim 1500 → payout 1400, remainingCap 600");
89	  it.todo("sword cap 2000: second claim 1500 → payout 600 (limited by remaining cap), remainingCap 0");
90	
91	  // === Payout rounding ===
92	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
93	
94	  // === Edge cases / error handling ===
95	  it.todo("quote with unknown item type → CLI exits non-zero, error on stderr, no results on stdout");
96	  it.todo("claim references damage for item not in policy → CLI exits non-zero, error on stderr");
97	  it.todo("claim damage entry with negative amount → CLI exits non-zero, error on stderr");
98	});
